using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — fixes for EF Core 9 breaking changes
class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...",
            "CatalogDb",
            // EF Core 9 breaking change: synchronous Cosmos I/O now throws by default.
            // Prefer converting to async; if that is not feasible, opt back in:
            cosmosOptions => cosmosOptions.AllowSynchronousIO());
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF Core 9 breaking change: default discriminator property changed
            // from "Discriminator" to "$type". Existing documents already store
            // "Discriminator", so explicitly preserve the old name.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

